    UPDATE bid
	    SET bid_status_idx = 2,
	        bid_moddate = NOW()
	    WHERE bid_idx = #{bidIdx}
	      AND auction_idx = #{auctionIdx}

    UPDATE bid
	    SET bid_status_idx = 3,
	        bid_moddate = NOW()
	    WHERE auction_idx = #{auctionIdx}
	      AND bid_idx != #{bidIdx}
	      AND bid_status_idx = 1
